interface MinimalResult {
  repo_url: string;
  repo_org: string;
  repo_name: string;
  language: string;
  last_updated: string;
  similarity_score: number;
  github_link: string;
  metadata: {
    stars?: number;
    license?: string;
  };
}

interface MCPSearchResponse {
  results: SearchResult[];
  metadata: { query: string; limit: number; resultCount: number; duration: number; };
  mode: ResultMode;  // "minimal" | "snippets" | "full"
}
